#include <bits/stdc++.h>
using namespace std;
#define ll long long
const ll MOD=2017;
const int MaxN=2e2;
ll cnt;
void matrix_self_product(ll a[MaxN][MaxN],int n){
    ll tmp[MaxN][MaxN];
    memset(tmp,0,sizeof(tmp));
    for(int i=0;i<n;i++)
    for(int j=0;j<n;j++)
    for(int m=0;m<n;m++)                
    tmp[i][j]=(tmp[i][j]+a[i][m]*a[m][j])%MOD;
    memcpy(a,tmp,sizeof(tmp));
}
void matrix_product(ll a[MaxN][MaxN],ll b[MaxN][MaxN],int n){
    ll tmp[MaxN][MaxN];
    memset(tmp,0,sizeof(tmp));
    for(int i=0;i<n;i++)
    for(int j=0;j<n;j++)
    for(int m=0;m<n;m++)                
    tmp[i][j]=(tmp[i][j]+a[i][m]*b[m][j])%MOD;
    memcpy(a,tmp,sizeof(tmp));
}
void matrix_fast_power(ll a[MaxN][MaxN],ll n,ll t){
    ll res[MaxN][MaxN];
    memset(res,0,sizeof(res));
    for(int i=0;i<n;i++)
        res[i][i]=1;
    ll tmp[MaxN][MaxN];
    memcpy(tmp,a,sizeof(tmp));
    for(ll i=t;i;i>>=1){
        if(i%2)matrix_product(res,tmp,n);
        matrix_self_product(tmp,n);
    }
    memcpy(a,res,sizeof(res));
}
int main(){
	ios::sync_with_stdio(false);
    ll a[MaxN][MaxN],n,m,u,v,t;
    cin>>n>>m;
    memset(a,0,sizeof(a));
    for(int i=0;i<m;i++){
    	cin>>u>>v;
    	a[u][v]=1;
    	a[v][u]=1;
	}
	for(int i=0;i<=n;i++){
		a[0][i]=1;
		a[i][i]=1;
	}
	cin>>t;
    matrix_fast_power(a,n+1,t);
    for(int i=0;i<=n;i++){
        cnt+=a[i][1];
        cnt%=MOD;
    }
    cout<<cnt;
    return 0;
}

