using namespace std;
long long n,s[4000502],M[4000502],cnt;//0不开1开 
int m,ma,t[502];
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>t[i];
		M[t[i]]++;
		ma=max(ma,t[i]);
	}
	for(int i=m+1;i<=ma+m-1;i++)s[i]=0x7fffffff;
	sort(&t[1],&t[n+1]);
	if(m<2){
		cout<<0;
		return 0;
	}
	for(int i=0;i<m;i++){//第一个板 
		for(int l=1;l<=n&&t[l]<=i;l++){
			s[i]+=(i-t[l])*M[t[l]];
		}
	}
	s[m]=s[0];
	for(int l=1;t[l]<=m;l++)if(t[l])s[m]+=(m-t[l])*M[t[l]];
	for(int i=m+1;i<=ma+m-1;i++){
		cnt=0;
		for(int j=i-m+1;j<=i-1;j++){
			cnt+=M[j]*(i-j);
		}
		for(int l=i-m;l>=max(0,i-2*m+1);l--){
			//cnt=s[l];
			//for(int j=l+1;j>=i-1;j++){
				
			//}
			s[i]=min(s[i],s[l]+cnt);
			cnt+=M[l]*(i-l);
		}
	}
	//for(int i=0;i<=ma+m-1;i++)cout<<s[i]<<' ';
	//cout<<'\n';
	//for(int i=0;i<=ma+m-1;i++)cout<<i<<' ';
	//cout<<'\n';
	for(int i=ma;i<=ma+m-1;i++)s[ma+m-1]=min(s[ma+m-1],s[i]);
	cout<<s[ma+m-1];
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,t[1005][1005][3],p=1;
//      无 太阳花 剑 
string a[1005][3];
struct xy{
	ll x,y;
}S,E,X[1000005];
struct A{
	ll x,flr,y;
};
queue<A>q;
bool vis[1005][1005][3];
void add(ll x2,ll y2,ll flr,ll v,ll x,ll y,ll flr2){
	//cout<<"A";
	//cout<<t[x2][y2][flr]<<' '<<t[x][y][flr2]+v<<'\n';//
	if(t[x2][y2][flr]>t[x][y][flr2]+v){
		//cout<<"B";
		t[x2][y2][flr]=t[x][y][flr2]+v;
		if(!vis[x2][y2][flr]){
			//cout<<"C";
			vis[x2][y2][flr]=1;
			q.push({x2,flr,y2});
		}
	}
}
void bfs(){
	q.push({S.x,0,S.y});
	xy fx[4]={{1,0},{0,1},{-1,0},{0,-1}};//下右上左 
	while(!q.empty()){
		A k=q.front();
		q.pop();
		ll x=k.x,flr=k.flr,y=k.y;
		vis[x][y][flr]=0;
		//cout<<x<<' '<<y<<' '<<flr<<' '<<t[x][y][flr]<<'\n';//
		for(int i=0;i<=3;i++){
			//cout<<"i="<<i<<'\n';//
			ll x2=x+fx[i].x,y2=y+fx[i].y;
			//cout<<"xy="<<x2<<','<<y2<<'\n';//
			if(a[x2][flr][y2]=='0'||a[x2][flr][y2]=='S'){
				//cout<<"O";//
				add(x2,y2,flr,1,x,y,flr);
			}
			else if(a[x2][flr][y2]=='X'){
				//cout<<"X";//
				if(t[x2][y2][flr]<=t[x][y][flr]+1)continue;
				add(x2,y2,flr,1,x,y,flr);
				for(int l=1;l<p;l++){
					if(X[l].x!=x2||X[l].y!=y2){
						add(X[l].x,X[l].y,flr,2,x,y,flr);
					}
				}
			}
			else if(a[x2][flr][y2]=='1'){
				//cout<<"a";//
				continue;
			}
			else if(a[x2][flr][y2]=='2'){
				//cout<<"b";//
				add(x2,y2,flr,4,x,y,flr);
			}
			else if(a[x2][flr][y2]=='3'){
				//cout<<"c";//
				add(x2,y2,flr,9,x,y,flr);
			}
			else if(a[x2][flr][y2]=='4'){
				//cout<<"d";//
				add(x2,y2,1,1,x,y,flr);
			}
			else if(a[x2][flr][y2]=='5'){
				add(x2,y2,flr,1,x,y,flr);
				add(x2,y2,2,5,x2,y2,flr);
			}
			else if(a[x2][flr][y2]=='E'){
				t[x2][y2][flr]=min(t[x2][y2][flr],t[x][y][flr]+1);
			}
		}
	}
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i][0];
		a[i][0]=' '+a[i][0];
		a[i][2]=a[i][1]=a[i][0];
		//cout<<a[i][0][5]<<'\n';//
		for(int l=1;l<=m;l++){
			t[i][l][0]=t[i][l][1]=t[i][l][2]=1000000000;

			if(a[i][0][l]=='X')X[p++]={i,l};
			else if(a[i][0][l]=='M')a[i][0][l]=a[i][1][l]=a[i][2][l]='0';
			else if(a[i][0][l]=='S'){
				S.x=i;S.y=l;
				t[i][l][0]=0;
			}
			else if(a[i][0][l]=='E'){
				E.x=i;E.y=l;
			}
			else if(a[i][1][l]=='2'||a[i][1][l]=='3'||a[i][1][l]=='4')a[i][1][l]=a[i][2][l]='0';
			else if(a[i][2][l]=='1'||a[i][2][l]=='5')a[i][2][l]='0';
		}
	}
	//cout<<"p="<<p<<'\n';//
	bfs();
	ll ans=min(t[E.x][E.y][0],min(t[E.x][E.y][1],t[E.x][E.y][2]));
	if(ans==1000000000)cout<<"We want to live in the TouHou World forever";
	else cout<<ans;
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,a,b,c,d,xh[1000002][2],dep[1000002][2],low[1000002][2],vis[1000002][2],cnt=1,jl=0,
in[1000002][2],p3=1,p2=1;
struct A{
	ll p,v;
};
A sta2[1000002];
vector<A>vec[1000002][2],sta[2000002];//0 jia 1 zhen fei
void dfs(ll k,ll p){
	//printf("k=%d p=%d\n",k,p);
	in[k][p]=1;
	sta2[p2++]={k,p};
	for(int i=0;i<vec[k][p].size()&&jl==0;i++){
		ll P=vec[k][p][i].p,V=vec[k][p][i].v;
		if(!vis[P][V]){
			dep[P][V]=low[P][V]=cnt++;
			vis[P][V]=1;
			dfs(P,V);
			low[k][p]=min(low[k][p],low[P][V]);
		}
		else{
			if(low[k][p]>dep[P][V]&&in[P][V]==1){
				low[k][p]=dep[P][V];
			}
		}
	}
	//printf("low[%d][%d]=%d  dep[%d][%d]=%d\n",k,p,low[k][p],k,p,dep[k][p]);
	if(low[k][p]==dep[k][p]){
		while(p2>1){
			sta[p3].push_back(sta2[p2-1]);
			xh[sta2[p2-1].p][sta2[p2-1].v]=p3;
			//printf("xh[%d][%d]=%d\n",sta2[p2-1].p,sta2[p2-1].v,p3);
			//printf("p2=%d\n",p2);
			in[sta2[p2-1].p][sta2[p2-1].v]=0;
			if(xh[sta2[p2-1].p][sta2[p2-1].v]==xh[sta2[p2-1].p][!sta2[p2-1].v]){
				//printf("%d %d\n",sta2[p2-1].p,sta2[p2-1].v);
				jl=1;
				return;
			}
			p2--;
			if(sta2[p2].p==k&&sta2[p2].v==p){
				//puts("B");
				break;
			}
		}
		p3++;
	}
}
int main(){
    ios::sync_with_stdio(false);
    cin>>n>>m;
    for(int i=1;i<=m;i++){
    	cin>>c>>a>>d>>b;
    	if(a==0&&b==0){
    		vec[c][1].push_back({d,0});
    		vec[d][1].push_back({c,0});
		}
		else if(a==0&&b==1){
			vec[c][1].push_back({d,1});
			vec[d][0].push_back({c,0});
		}
		else if(a==1&&b==0){
			vec[c][0].push_back({d,0});
			vec[d][1].push_back({c,1});
		}
		else{
			vec[c][0].push_back({d,1});
			vec[d][0].push_back({c,1});
		}
	}
	for(int i=1;i<=n;i++){
		if(vis[i][0]==0){
			low[i][0]=dep[i][0]=cnt++;
			vis[i][0]=1;
			dfs(i,0);
