void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	if(l==r){
		sum[k]=a[l];
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	sum[k]=sum[k*2]+sum[k*2+1];
}
void add(ll k,ll l,ll r){
	if(L[k]==R[k]){
		sum[k]=sqrt(sum[k]);
