	ll mid=(L[k]+R[k])/2;
	if(l<=mid&&sum[k*2]>R[k*2]-L[k*2]+1)add(k*2,l,r);
	if(r>=mid+1&&sum[k*2+1]>R[k*2+1]-L[k*2+1]+1)add(k*2+1,l,r);
	sum[k]=sum[k*2]+sum[k*2+1];
}
ll cha(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		return sum[k];
	}
	ll mid=(L[k]+R[k])/2,res=0;
	if(l<=mid)res+=cha(k*2,l,r);
	if(r>=mid+1)res+=cha(k*2+1,l,r);
