	}
	return res;
}
ll cha1(ll p1,ll p2){
	ll res=0;
	while(top[p1]!=top[p2]){
		if(dep[top[p1]]<dep[top[p2]])swap(p1,p2);
		res+=cha(1,id[top[p1]],id[p1]);
		p1=fa[top[p1]];
	}
	if(dep[p1]<dep[p2])swap(p1,p2);
	res+=cha(1,id[p2],id[p1]);
	return res;
}
void dfs1(ll u,ll f){
	dep[u]=dep[f]+1;
	fa[u]=f;
	sz[u]=1;
	for(int i=0;i<vec[u].size();i++){
		if(vec[u][i]!=f){
			dfs1(vec[u][i],u);
			sz[u]+=sz[vec[u][i]];
			if(sz[son[u]]<sz[vec[u][i]])son[u]=vec[u][i];
		}
	}
}
void dfs2(ll u,ll t){
	id[u]=++cnt,nw[cnt]=w[u],top[u]=t;
	if(!son[u])return;
	dfs2(son[u],t);
	for(int i=0;i<vec[u].size();i++){
		if(vec[u][i]!=fa[u]&&vec[u][i]!=son[u]){
			dfs2(vec[u][i],vec[u][i]);
		}
	}
}
