void build(ll K,ll l,ll r){
	sum[K]={l,r,0,nw[r],nw[r]};
	if(l==r)return;
	ll mid=(l+r)/2;
	build(K*2,l,mid);
	build(K*2+1,mid+1,r);
	sum[K].sum=sum[K*2].sum+sum[K*2+1].sum;
	sum[K].ma=max(sum[K*2].ma,sum[K*2+1].ma);
}
void push(ll K){
	sum[K*2].add+=sum[K].add;
	sum[K*2].sum+=sum[K].add*(sum[K*2].r-sum[K*2].l+1);
	sum[K*2+1].add+=sum[K].add;
	sum[K*2+1].sum+=sum[K].add*(sum[K*2+1].r-sum[K*2+1].l+1);
	sum[K].add=0;
}
void modify2(ll K,ll l,ll r,ll v){
	if(l<=sum[K].l&&r>=sum[K].r){
		sum[K].sum=v;
		sum[K].ma=v;
		return;
	}
	ll mid=(sum[K].l+sum[K].r)/2;
	if(l<=mid){
		modify2(K*2,l,r,v);
	}
	if(r>mid){
		modify2(K*2+1,l,r,v);
	}
	sum[K].sum=sum[K*2].sum+sum[K*2+1].sum;
	sum[K].ma=max(sum[K*2].ma,sum[K*2+1].ma);
}
ll cha(ll K,ll l,ll r){
	if(sum[K].l>=l&&sum[K].r<=r)return sum[K].sum;
	push(K);
	ll mid=(sum[K].l+sum[K].r)/2,res=0;
	if(l<=mid){
		res+=cha(K*2,l,r);
	}
	if(r>mid){
		res+=cha(K*2+1,l,r);
	}
	return res;
}
ll cha3(ll K,ll l,ll r){
	if(sum[K].l>=l&&sum[K].r<=r)return sum[K].ma;
	push(K);
	ll mid=(sum[K].l+sum[K].r)/2,res=-0x7fffffff;
	if(l<=mid){
		res=max(res,cha3(K*2,l,r));
	}
	if(r>mid){
		res=max(res,cha3(K*2+1,l,r));
	}
	return res;
}
ll cha1(ll p1,ll p2){
	ll res=0;
	while(top[p1]!=top[p2]){
		if(dep[top[p1]]<dep[top[p2]])swap(p1,p2);
		res+=cha(1,id[top[p1]],id[p1]);
		p1=fa[top[p1]];
	}
	if(dep[p1]<dep[p2])swap(p1,p2);
	res+=cha(1,id[p2],id[p1]);
	return res;
}
ll cha2(ll p1,ll p2){
	ll res=-0x7fffffff;
	while(top[p1]!=top[p2]){
		if(dep[top[p1]]<dep[top[p2]])swap(p1,p2);
		res=max(res,cha3(1,id[top[p1]],id[p1]));
		p1=fa[top[p1]];
	}
	if(dep[p1]<dep[p2])swap(p1,p2);
	res=max(res,cha3(1,id[p2],id[p1]));
