#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=5e5+5;
const ll mod=1e9+9;
ll n,m,a[N],b[N],hec[N],hey[N],he[N],f[N];//f[i]:到第i人至少要多少房间 sum[k]:(he[i])k区间中的最小用房数 
ll sum[N*4*2],L[N*4*2],R[N*4*2];
void build(int k,int l,int r){
	L[k]=l;R[k]=r;
	sum[k]=0x7fffffff;
	if(l==r){
		return;
	}
	int mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
}
void add(int k,int p,ll v){
	if(L[k]>=p&&R[k]<=p){
		sum[k]=min(sum[k],v);
		return;
	}
	int mid=(L[k]+R[k])/2;
	if(p<=mid)add(k*2,p,v);
	else add(k*2+1,p,v);
	sum[k]=min(sum[k*2],sum[k*2+1]);
}
ll cha(int k,int l,int r){
	if(l<=L[k]&&r>=R[k]){
		return sum[k];
	}
	int mid=(L[k]+R[k])/2;
	ll res=0x7fffffff;
	if(l<=mid)res=min(res,cha(k*2,l,r));
	if(r>=mid+1)res=min(res,cha(k*2+1,l,r));
	return res;
}
