		hey[i]=hey[i-1]+((bool)(a[i]==1));
		he[i]=hey[i]-hec[i];
	}
	build(1,1,n*2+5);
	add(1,n+2,0);
	f[0]=0x7fffffff;
	ll k=a[1],mn=0;
	for(int i=1;i<=n;i++){
		if(k!=a[i]){
			mn=f[i-1];
		}
		int l=he[i]-m,r=he[i]+m;//l<=he[j]<=r 
