				fa[findf(k.u)]=fa[findf(k.v)];
				res+=k.w;
	            if(jl==n)q2.push_back(k);
				if(k.u<=n&&k.v<=n)cnt++;
				if(cnt==jl-1)break;
			}
		}
    }
	return res;
}
