using namespace std;
long long t,n,m,cnt,p[102][102],dp[100002];
int main(){
	//freopen("souvenir.in","r",stdin);
	//freopen("souvenir.out","w",stdout);
	cin>>t>>n>>m;
	for(int i=1;i<=t;i++){
		for(int l=1;l<=n;l++){
			cin>>p[i][l];
		}
	}
	if(t==1){
		cout<<m;
		return 0;
	}
	if(n==1){
		for(int i=2;i<=t;i++){
			if(p[i][1]>p[i-1][1]){
				m=m%p[i-1][1]+m/p[i-1][1]*p[i][1];
			}
		}
		cout<<m;
		return 0;
	}
	for(int i=2;i<=t;i++){
		memset(dp,0,100000);
		for(int l=1;l<=n;l++){
			for(int j=p[i-1][l];j<=m;j++){
				dp[j]=max(dp[j],dp[j-p[i-1][l]]+p[i][l]-p[i-1][l]);
			}
		}
		m+=dp[m];
	}
	cout<<m;
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,trie[6000005][10],cnt[6000005],p=1,opt;
vector<int>t[6000005];
void add(string s,int v){
	ll k=0;
	for(int i=0;i<s.length();i++){
		if(!trie[k][s[i]-'a'])trie[k][s[i]-'a']=p++;
		k=trie[k][s[i]-'a'];
		cnt[k]+=v;
		if(cnt[k]>t[k].size())t[k].push_back(opt);
	}
}
int cha(string s,int v){
	ll k=0;
	for(int i=0;i<s.length();i++){
		if(!trie[k][s[i]-'a'])return -1;
		k=trie[k][s[i]-'a'];
	}
	if(v<t[k].size())return t[k][v];
	return -1;
}
int main(){
	ios::sync_with_stdio(false);
	ll ANS=0;
	cin>>n;
	for(opt=1;opt<=n;opt++){
		int o;string s;
		cin>>o;
		if(o==1){
			cin>>s;
			add(s,1);
		}
		else if(o==2){
			cin>>s;
			add(s,-1);
		}
		else{
			cin>>s;
			int a,b,c;
			cin>>a>>b>>c;
			ANS=cha(s,(a*abs(ANS)+b)%c);
			cout<<ANS<<'\n';
		}
	}
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
int n,m,op,a,b,d[10000002];
inline int read(){
	int x=0,f=1;char ch=getchar();
	while (ch<'0'||ch>'9'){if (ch=='-') f=-1;ch=getchar();}
	while (ch>='0'&&ch<='9'){x=x*10+ch-48;ch=getchar();}
	return x*f;
}
void JIA(int A,int B){//加 
	while(A<=n){
		d[A]++;
		A+=A&-A;
	}
	while(B<=n){
		d[B]--;
		B+=B&-B;
	}
}
int CHA(int A){//查 
	int sum = 0;
	while (A >= 1) {
		sum += d[A];
		A -= A & -A;
	}
	return sum;
}
int main(){
//	ios::sync_with_stdio(false);
	n=read();m=read();
	for(int i=1;i<=m;i++){
		op=read();
		if(op){
			a=read();
			cout<<CHA(a)<<'\n';
		}
		else{
			a=read();
			b=read();
			JIA(a, b+1);
		}
	}
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
long long n,ml,md,c1,c2,y,dis[5002],cnt[5002],in_q[5002],jl;
struct A{int to,cost;};
vector<A>v[5002];
queue<int>q;
void SPFA(int k){
	q.push(k);
	for(int i=1;i<=n;i++){
		dis[i]=0x7fffffff;
	}
	dis[k]=0;
	while(!q.empty()){
		int cur_pos=q.front();
		q.pop();
		in_q[cur_pos]=0;
		if(cnt[cur_pos]>=n){
			jl=1;
			cout<<"-1";
			return;
		}
		for(int i=0;i<v[cur_pos].size();i++){
			int cur_to = v[cur_pos][i].to;
			int cur_cost = v[cur_pos][i].cost;
			if(dis[cur_to]>dis[cur_pos]+cur_cost){
				dis[cur_to]=cur_cost+dis[cur_pos];
				if(!in_q[cur_to]){
					q.push(cur_to);
					in_q[cur_to]=1;
					cnt[cur_to]++;
				}
			}
		}
	}
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>ml>>md;
	for(int i=2;i<=n;i++){
		v[i].push_back(A{i-1,0});
		//v[i-1].push_back(A{i,0});
	}
	for(int i=1;i<=ml;i++){
		cin>>c1>>c2>>y;
		v[c1].push_back(A{c2,y});
		//v[c2].push_back(A{c1,-y});
	}
	for(int i=1;i<=md;i++){
		cin>>c1>>c2>>y;
		v[c2].push_back(A{c1,-y});
		//v[c1].push_back(A{c2,y});
	}
	for(int i=1;i<=n;i++){
		v[0].push_back(A{i,0});
		dis[i]=0x7fffffff;
	}
	SPFA(0);
	if(!jl)SPFA(1);
	if(dis[n]==0x7fffffff){
		cout<<"-2";
		return 0;
	}
	if(!jl)cout<<dis[n];
	return 0;
}

#include <bits/stdc++.h>
using namespace std;
long long n,m,k,u,v,w,val[500002],mi=0x7fffffff;
struct A{long long x,val;};
bool operator<(A B,A C){return B.val>C.val;}
priority_queue<A>q;
vector<A>vec[10002];
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m>>k;
	for(int i=1;i<=(k+1)*n;i++)val[i]=0x7fffffff;
	for(int i=1;i<=m;i++){
		cin>>u>>v>>w;
		for(int l=0;l<=k;l++){
			vec[u+(l*n)].push_back(A{v+(l*n),w});
			vec[v+(l*n)].push_back(A{u+(l*n),w});
		}
		for(int l=0;l<k;l++){
			vec[u+(l*n)].push_back(A{v+((l+1)*n),w/2});
			vec[v+(l*n)].push_back(A{u+((l+1)*n),w/2});
		}
	}
	q.push(A{1,0});
	while(!q.empty()){
		A K=q.top();
		q.pop();
		if(val[K.x]==0x7fffffff){
			val[K.x]=K.val;
			for(int i=0;i<vec[K.x].size();i++){
				q.push(A{vec[K.x][i].x,vec[K.x][i].val+val[K.x]});
			}
		}
	}
	for(int i=1;i<=min(k+1,n);i++){
		mi=min(mi,val[i*n]);
	}
	cout<<mi;
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,a[45];
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=0;i<n;i++){
		cin>>a[i];
		if(a[i]>m){
			i--;
			n--;
		}
	}
	vector<ll>v1;
	for(int st=(1<<n/2)-1;st;st--){
		ll k=0;bool jl=0;
		for(int l=st;l;l&=l-1){
			ll o=__lg(l&-l);
			k+=a[o];
			if(k>m){
				jl=1;
				break;
			}
		}
		if(jl==0){
			v1.push_back(k);
		}
	}
	vector<ll>v2;
	for(int st=(1<<(n-n/2))-1;st;st--){
		ll k=0;bool jl=0;
		for(int l=st;l;l&=l-1){
			ll o=__lg(l&-l);
			k+=a[o+n/2];
			if(k>m){
				jl=1;
				break;
			}
		}
		if(jl==0){
			v2.push_back(k);
		}
	}
	v1.push_back(0);
	v2.push_back(0);
	sort(v1.begin(),v1.end());
	sort(v2.begin(),v2.end());
	ll ans=0;
	for(int i=0;i<v1.size();i++){
		ll p=upper_bound(v2.begin(),v2.end(),m-v1[i])-v2.begin();
		ans+=p;
	}
	cout<<ans;
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define N 500002
#define eps 0.0000000001
#define delT 0.999
ll n;
double l,a_last,a_best;
struct P{
	double x,y;
}p[102],p_last,p_best;
double energy(P k){
	double res=0x7fffffff;
	for(int i=1;i<=n;i++){
		res=min(res,sqrt((p[i].x-k.x)*(p[i].x-k.x)+(p[i].y-k.y)*(p[i].y-k.y)));
	}
	return -res;
}
P move(P k,double T){
	double dx=2*rand()-RAND_MAX,dy=2*rand()-RAND_MAX;
	return {max((double)0,min(k.x+dx*T,l)),max((double)0,min(l,k.y+dy*T))};
}
void SA(){
	double T=200;
	while(T>=eps){
		P p_cur=move(p_last,T);
		double a_cur=energy(p_cur);
		if(a_cur<a_last){
			a_last=a_cur;
			p_last=p_cur;
		}
		else if(exp((a_last-a_cur)/T)*RAND_MAX>rand()){
			a_last=a_cur;
			p_last=p_cur;
		}
		if(a_cur<a_best){
			a_best=a_cur;
			p_best=p_cur;
		}
		T*=delT;
	}
}
int main(){
	//ios::sync_with_stdio(false);
	cin>>n>>l;
	for(int i=1;i<=n;i++){
		cin>>p[i].x>>p[i].y;
	}
	p_last=p_best={l/2,l/2};
	a_last=a_best=energy({l/2,l/2});
	SA();
	SA();
	SA();
	if(-a_best*n>l)printf("%.3f %.3f",p_best.x,p_best.y);
	else cout<<"GG";
	return 0;
};

